SELECT AVG(2023 - CAST(strftime('%Y', date_of_birth) AS INT)) AS average_age
FROM senators
WHERE party = 'D';

SELECT senator_id, vote_cast
FROM voting_records
WHERE voting_phase = 'Floor Vote';

SELECT name, state
FROM senators
WHERE party = 'R';

SELECT committee_name
FROM committees
WHERE committee_type = 'Standing';

SELECT party, COUNT(*)
FROM senators
GROUP BY party;

SELECT senator_id
FROM social_media
WHERE platform = 'Twitter' AND followers > 30000;

SELECT strftime('%Y', created_at) AS year, COUNT(tag_name) AS number_of_tags
FROM committee_tag
GROUP BY year;
